import{_ as e,o as i,c as r,ah as t}from"./chunks/framework.Bg572dcY.js";const b=JSON.parse('{"title":"CI/CD","description":"","frontmatter":{"title":"CI/CD","order":4},"headers":[],"relativePath":"server/distribute/cloud/cicd/index.md","filePath":"server/distribute/cloud/cicd/index.md"}'),n={name:"server/distribute/cloud/cicd/index.md"};function h(l,a,o,c,d,s){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to “CI/CD”">​</a></h1><p>CI/CD（Continuous Integration/Continuous Deployment）是持续集成和持续部署的缩写，是现代软件工程的核心实践。CI/CD 自动化构建、测试、部署流程，提高软件交付速度和质量。</p><h2 id="ci-cd-的概念" tabindex="-1">CI/CD 的概念 <a class="header-anchor" href="#ci-cd-的概念" aria-label="Permalink to “CI/CD 的概念”">​</a></h2><h3 id="ci-continuous-integration-持续集成" tabindex="-1">CI（Continuous Integration，持续集成） <a class="header-anchor" href="#ci-continuous-integration-持续集成" aria-label="Permalink to “CI（Continuous Integration，持续集成）”">​</a></h3><p>持续集成是开发者频繁提交代码到共享仓库，每次提交自动触发构建和测试。持续集成的目标是快速发现和修复错误，减少集成成本。</p><p>持续集成的实践：频繁提交（每天多次提交）、自动化构建（自动编译、打包）、自动化测试（单元测试、集成测试）、快速反馈（构建失败立即通知）。</p><h3 id="cd-continuous-deployment-持续部署" tabindex="-1">CD（Continuous Deployment，持续部署） <a class="header-anchor" href="#cd-continuous-deployment-持续部署" aria-label="Permalink to “CD（Continuous Deployment，持续部署）”">​</a></h3><p>持续部署是将通过测试的代码自动部署到生产环境。持续部署的目标是缩短交付周期，快速向用户交付价值。</p><p>持续部署的实践：自动化部署（自动部署到各个环境）、基础设施即代码（Infrastructure as Code）、灰度发布（先发布到少量实例）、监控告警（监控部署状态和应用性能）。</p><h3 id="cd-continuous-delivery-持续交付" tabindex="-1">CD（Continuous Delivery，持续交付） <a class="header-anchor" href="#cd-continuous-delivery-持续交付" aria-label="Permalink to “CD（Continuous Delivery，持续交付）”">​</a></h3><p>持续交付是将通过测试的代码自动部署到类生产环境，但需要人工确认才能部署到生产环境。持续交付是持续部署的前一步，增加了人工确认环节。</p><h2 id="ci-cd-的流程" tabindex="-1">CI/CD 的流程 <a class="header-anchor" href="#ci-cd-的流程" aria-label="Permalink to “CI/CD 的流程”">​</a></h2><h3 id="代码提交" tabindex="-1">代码提交 <a class="header-anchor" href="#代码提交" aria-label="Permalink to “代码提交”">​</a></h3><p>开发者提交代码到 Git 仓库（GitLab、GitHub、Gitee），触发 CI/CD 流程。</p><h3 id="构建阶段" tabindex="-1">构建阶段 <a class="header-anchor" href="#构建阶段" aria-label="Permalink to “构建阶段”">​</a></h3><p>拉取代码、编译代码、构建镜像、推送到镜像仓库。</p><h3 id="测试阶段" tabindex="-1">测试阶段 <a class="header-anchor" href="#测试阶段" aria-label="Permalink to “测试阶段”">​</a></h3><p>运行单元测试、集成测试、端到端测试、安全扫描。</p><h3 id="部署阶段" tabindex="-1">部署阶段 <a class="header-anchor" href="#部署阶段" aria-label="Permalink to “部署阶段”">​</a></h3><p>部署到开发环境、部署到测试环境、部署到预发布环境、部署到生产环境。</p><h3 id="监控阶段" tabindex="-1">监控阶段 <a class="header-anchor" href="#监控阶段" aria-label="Permalink to “监控阶段”">​</a></h3><p>监控应用性能、收集应用日志、设置告警规则。</p><h2 id="ci-cd-工具" tabindex="-1">CI/CD 工具 <a class="header-anchor" href="#ci-cd-工具" aria-label="Permalink to “CI/CD 工具”">​</a></h2><h3 id="jenkins" tabindex="-1">Jenkins <a class="header-anchor" href="#jenkins" aria-label="Permalink to “Jenkins”">​</a></h3><p>Jenkins 是开源的 CI/CD 工具，功能强大、插件丰富。</p><p>Jenkins 的优势：开源免费、插件生态丰富、自定义能力强。</p><p>Jenkins 的问题：配置复杂、需要维护服务器、插件可能有安全漏洞。</p><h3 id="gitlab-ci-cd" tabindex="-1">GitLab CI/CD <a class="header-anchor" href="#gitlab-ci-cd" aria-label="Permalink to “GitLab CI/CD”">​</a></h3><p>GitLab CI/CD 是 GitLab 内置的 CI/CD 工具，与 Git 仓库紧密集成。</p><p>GitLab CI/CD 的优势：与 Git 仓库集成、配置简单（.gitlab-ci.yml）、内置镜像仓库、内置容器注册表。</p><p>GitLab CI/CD 的问题：仅支持 GitLab、功能相对简单。</p><h3 id="github-actions" tabindex="-1">GitHub Actions <a class="header-anchor" href="#github-actions" aria-label="Permalink to “GitHub Actions”">​</a></h3><p>GitHub Actions 是 GitHub 的 CI/CD 工具，与 GitHub 仓库紧密集成。</p><p>GitHub Actions 的优势：与 GitHub 仓库集成、配置简单（workflow YAML）、丰富的 Marketplace、免费额度慷慨。</p><p>GitHub Actions 的问题：仅支持 GitHub、学习曲线陡峭。</p><h3 id="circleci" tabindex="-1">CircleCI <a class="header-anchor" href="#circleci" aria-label="Permalink to “CircleCI”">​</a></h3><p>CircleCI 是云原生的 CI/CD 工具，配置简单、性能好。</p><p>CircleCI 的优势：云原生、配置简单、性能好、Docker 支持。</p><p>CircleCI 的问题：免费额度有限、国内访问慢。</p><h3 id="argocd" tabindex="-1">ArgoCD <a class="header-anchor" href="#argocd" aria-label="Permalink to “ArgoCD”">​</a></h3><p>ArgoCD 是 Kubernetes 的持续部署工具，基于 GitOps 理念。</p><p>ArgoCD 的优势：GitOps（Git 作为单一数据源）、声明式部署、同步状态可视化、支持多种 Helm Chart。</p><p>ArgoCD 的问题：仅支持 Kubernetes、学习曲线陡峭。</p><h2 id="gitops" tabindex="-1">GitOps <a class="header-anchor" href="#gitops" aria-label="Permalink to “GitOps”">​</a></h2><h3 id="gitops-的概念" tabindex="-1">GitOps 的概念 <a class="header-anchor" href="#gitops-的概念" aria-label="Permalink to “GitOps 的概念”">​</a></h3><p>GitOps 是一种基于 Git 的运维模式，Git 仓库是单一数据源，Git 仓库的变化自动触发部署。</p><p>GitOps 的流程：修改 Git 仓库的配置、CI/CD 检测到变化、自动部署到集群、集群状态同步到 Git 仓库。</p><h3 id="gitops-的优势" tabindex="-1">GitOps 的优势 <a class="header-anchor" href="#gitops-的优势" aria-label="Permalink to “GitOps 的优势”">​</a></h3><p>单一数据源：Git 仓库是单一数据源，配置和代码在一起，便于版本控制和回滚。</p><p>声明式部署：使用 Kubernetes 的声明式 API，Git 仓库定义期望状态，集群自动同步。</p><p>自动化部署：Git 仓库的变化自动触发部署，无需人工干预。</p><p>审计日志：Git 仓库记录所有变更，便于审计和问题排查。</p><h3 id="gitops-的工具" tabindex="-1">GitOps 的工具 <a class="header-anchor" href="#gitops-的工具" aria-label="Permalink to “GitOps 的工具”">​</a></h3><p>ArgoCD：Kubernetes 的持续部署工具，支持 GitOps。</p><p>Flux：GitOps 工具，支持 Kubernetes。</p><p>Rudder：多云 GitOps 工具，支持 Kubernetes、Terraform。</p><h2 id="ci-cd-的最佳实践" tabindex="-1">CI/CD 的最佳实践 <a class="header-anchor" href="#ci-cd-的最佳实践" aria-label="Permalink to “CI/CD 的最佳实践”">​</a></h2><h3 id="自动化一切" tabindex="-1">自动化一切 <a class="header-anchor" href="#自动化一切" aria-label="Permalink to “自动化一切”">​</a></h3><p>自动化构建、自动化测试、自动化部署，减少人工干预，提高效率。</p><h3 id="快速反馈" tabindex="-1">快速反馈 <a class="header-anchor" href="#快速反馈" aria-label="Permalink to “快速反馈”">​</a></h3><p>构建和测试要快，失败立即通知开发者。快速反馈可以快速发现和修复错误。</p><h3 id="小步提交" tabindex="-1">小步提交 <a class="header-anchor" href="#小步提交" aria-label="Permalink to “小步提交”">​</a></h3><p>频繁提交小步代码，避免大步提交导致集成问题。小步提交可以快速发现问题，减少排查成本。</p><h3 id="测试覆盖" tabindex="-1">测试覆盖 <a class="header-anchor" href="#测试覆盖" aria-label="Permalink to “测试覆盖”">​</a></h3><p>单元测试、集成测试、端到端测试，确保代码质量。测试覆盖率要高，关键路径必须有测试。</p><h3 id="环境一致性" tabindex="-1">环境一致性 <a class="header-anchor" href="#环境一致性" aria-label="Permalink to “环境一致性”">​</a></h3><p>开发、测试、生产环境尽量一致，避免环境差异导致问题。使用容器、Helm 保证环境一致。</p><h3 id="灰度发布" tabindex="-1">灰度发布 <a class="header-anchor" href="#灰度发布" aria-label="Permalink to “灰度发布”">​</a></h3><p>先部署到少量实例，验证后全量发布，降低风险。使用蓝绿部署、金丝雀发布实现灰度发布。</p><h3 id="监控告警" tabindex="-1">监控告警 <a class="header-anchor" href="#监控告警" aria-label="Permalink to “监控告警”">​</a></h3><p>监控部署状态和应用性能，异常时及时告警。设置告警规则，避免告警风暴。</p><h3 id="回滚机制" tabindex="-1">回滚机制 <a class="header-anchor" href="#回滚机制" aria-label="Permalink to “回滚机制”">​</a></h3><p>部署失败时快速回滚到之前的版本，减少故障影响。保持历史版本，便于快速回滚。</p><h3 id="安全扫描" tabindex="-1">安全扫描 <a class="header-anchor" href="#安全扫描" aria-label="Permalink to “安全扫描”">​</a></h3><p>扫描镜像漏洞、扫描代码漏洞、扫描依赖漏洞，及时修复安全问题。</p><h3 id="文档维护" tabindex="-1">文档维护 <a class="header-anchor" href="#文档维护" aria-label="Permalink to “文档维护”">​</a></h3><p>维护 CI/CD 流程文档，确保团队成员了解流程。记录部署手册，便于故障排查。</p><p>CI/CD 是现代软件工程的核心实践，理解 CI/CD 的原理和最佳实践，有助于构建高效的软件交付流程。</p>',78)])])}const C=e(n,[["render",h]]);export{b as __pageData,C as default};
